%[text] # 例8.6（ブロックDHT係数の分布）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example08_06"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";

close all
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');

figure(1) %[output:83a5851b]
subplot(1,2,1) %[output:83a5851b]
imshow(X) %[output:83a5851b]
title('原画像') %[output:83a5851b]
%%
%[text] ## 分析処理
%[text] 直交ウェーブレット変換
nlevels = 3;

% Preparation of filters for wavelets
iswtb = license('checkout','wavelet_toolbox');
if iswtb % Functions in Wavelet Toolbox are used %[output:group:3ed101d2]
    dwtmode('per') %[output:634fb21e]
    wname = "haar"; %[control:dropdown:5881]{"position":[13,19]}
    [h0,h1,f0,f1] = wfilters(wname);
else
    import msip.ezwavedec2
    import msip.ezwaverec2
    h0 = [1 1]/sqrt(2);
    h1 = [-1 1]/sqrt(2);
    f0 = [1 1]/sqrt(2);
    f1 = [1 -1]/sqrt(2);
    clear H  F
    % Analysis bi-variate filters
    H.h00 = h0(:)*h0(:).';
    H.h01 = h0(:)*h1(:).';
    H.h10 = h1(:)*h0(:).';
    H.h11 = h1(:)*h1(:).';
    % Synthesis bi-variate filters
    F.f00 = f0(:)*f0(:).';
    F.f01 = f0(:)*f1(:).';
    F.f10 = f1(:)*f0(:).';
    F.f11 = f1(:)*f1(:).';
end %[output:group:3ed101d2]
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');

figure(1)
imshow(X) %[output:925a4d5b]
title('原画像') %[output:925a4d5b]
%[text] 分析処理 (Analysis process)
if iswtb
    [coefs,scales] = wavedec2(X,nlevels,h0,h1);
    % Reconstruction to check PR
    Y = waverec2(coefs,scales,f0,f1);
else
    [coefs,scales] = ezwavedec2(X,nlevels,H);
    % Reconstruction to check PR%
    Y = ezwaverec2(coefs,scales,F);
end
assert(norm(X-Y,"fro")^2/numel(X)<1e-18,'Perfect reconstruction is violated.')
%%
%[text] ### 変換係数の配列化 (Alignment of coefficients)
C = aligncoefs(coefs,scales);
figure(2) %[output:031a2248]
imshow(abs(C)) %[output:031a2248]
%%
%[text] ### 変換係数の抽出 (Extraction  of coefficients)
s = extractcoefs(coefs,scales);
%%
%[text] ### 変換係数の分布
%[text] (Distribution of Coefs.)
nchs = length(s);
for ich = 1:nchs %[output:group:022a4fb9]
    figure %[output:98d7caff] %[output:30308f7b] %[output:6260dce9] %[output:57e1b57d] %[output:046ef748] %[output:2e64f358] %[output:8e2000b4] %[output:96c1ea9b] %[output:3ba9ed78] %[output:1443f0b0]
    subplot(1,2,1) %[output:98d7caff] %[output:30308f7b] %[output:6260dce9] %[output:57e1b57d] %[output:046ef748] %[output:2e64f358] %[output:8e2000b4] %[output:96c1ea9b] %[output:3ba9ed78] %[output:1443f0b0]
    if ich == 1
        imshow(s{ich}*pow2(-nlevels))
    else
        imshow(s{ich}+.5)
    end 
    subplot(1,2,2)
    histogram(s{ich}(:))
    axis square
    drawnow
end %[output:group:022a4fb9]
%[text] ### 
%%
%[text] ### 関数定義
%[text] (Definition of function)
%[text] 変換係数の配列化 (Alighment of coefficients)
function c00 = aligncoefs(coefs,scales)
nlevels = size(scales,1)-2;
pos = 0;
dim = scales(1,:);
nel = prod(dim);
c00 = reshape(coefs(pos+1:pos+nel),dim)/(2^nlevels);
pos = nel;
for ilv = 1:nlevels
    dim = scales(ilv+1,:);
    nel = prod(dim);
    %
    c01 = abs(reshape(coefs(pos+1:pos+nel),dim));
    pos = pos + nel;
    %
    c10 = abs(reshape(coefs(pos+1:pos+nel),dim));
    pos = pos + nel;
    %
    c11 = abs(reshape(coefs(pos+1:pos+nel),dim));
    pos = pos + nel;
    %
    c00 = [ c00 c01; c10 c11 ];
end
end
%[text] ### 変換係数の抽出
%[text] (Extraction of Coefs.)
function s = extractcoefs(coefs,scales)
nscales = size(scales,1)-1;
s = cell(3*(nscales-1)+1,1);
sidx = 1;
ndims = scales(1,:);
eidx = sidx + prod(ndims) - 1;
s{1} = reshape(coefs(sidx:eidx),ndims);
sidx = eidx + 1; 
ich = 2;
for iscale = 2:nscales
    ndims = scales(iscale,:);
    for iband = 1:3
        eidx = sidx + prod(ndims) - 1;
        s{ich} = reshape(coefs(sidx:eidx),ndims);
        sidx = eidx + 1;
        ich = ich + 1;
    end
end
end
